int segA = 2, segB = 3, segC = 4, segD = 5, segE = 6, segF = 7, segG = 8;
int btnAdd = 9, btnSub = 10;
int counter = 0;
int lastAddState = HIGH, lastSubState = HIGH;

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  pinMode(btnAdd, INPUT_PULLUP);
  pinMode(btnSub, INPUT_PULLUP);
  displayDigit(0);
}

void loop() {
  int addState = digitalRead(btnAdd);
  int subState = digitalRead(btnSub);

  if (addState == LOW && lastAddState == HIGH) {
    counter = (counter + 1) % 10;
    displayDigit(counter);
  }
  lastAddState = addState;

  if (subState == LOW && lastSubState == HIGH) {
    counter = (counter - 1 + 10) % 10;
    displayDigit(counter);
  }
  lastSubState = subState;

  delay(20);
}

void displayDigit(int n) {
